const item = $input.first() ?? { json: {}, binary: {} };
const json = {};
if (Array.isArray(item.json?.designHistory)) {
  json.designHistory = item.json.designHistory;
}

const binary = {};
for (const [name, value] of Object.entries(item.binary ?? {})) {
  if (name === 'requirements' || name === 'designSpec' || name === 'designZip' || name === 'reviewZip' || /^design_iteration_\d+$/.test(name)) {
    binary[name] = value;
  }
}

return [{
  json,
  ...(Object.keys(binary).length ? { binary } : {}),
}];

const item = $input.first() ?? { json: {}, binary: {} };
const json = { ...(item.json ?? {}) };
const binary = { ...(item.binary ?? {}) };

const getNodeItemSafe = (nodeName) => {
  if (typeof $items !== 'function') return null;
  try {
    return ($items(nodeName) || [])[0] || null;
  } catch {
    return null;
  }
};

// Force the latest ZIP from DESIGN - Create Design so merge/input ordering cannot reintroduce stale binaries.
const createDesignItem = getNodeItemSafe('DESIGN - Create Design');
const latestReviewZip = createDesignItem?.binary?.reviewZip || createDesignItem?.binary?.designZip || null;
if (latestReviewZip) {
  binary.reviewZip = latestReviewZip;
  binary.designZip = latestReviewZip;
} else if (binary.reviewZip) {
  // Fallback: keep previous behavior when direct node lookup is unavailable.
  binary.designZip = binary.reviewZip;
}

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const buildDesignReviewAssets = ({ history, currentIterationNumber, currentZipDownloadUrl, restoreError }) => {
  const currentDownloadUrl = String(currentZipDownloadUrl ?? '').trim();
  const currentDownloadHtml = currentDownloadUrl
    ? `<p><a href="${escapeHtml(currentDownloadUrl)}" download target="_blank" rel="noopener noreferrer">Download current Design ZIP</a></p>`
    : '';

  const historyItemsHtml = history.map((entry) => {
    const iterationNumber = Number(entry.iterationNumber ?? 0) || 0;
    const revisionNumber = Number(entry.revisionNumber ?? 0) || 0;
    const currentTag = iterationNumber === currentIterationNumber ? ' <strong>(current)</strong>' : '';
    const entryDownloadUrl = String(entry.zipDownloadUrl ?? '').trim();
    const entryDownloadHtml = entryDownloadUrl
      ? `<a href="${escapeHtml(entryDownloadUrl)}" download target="_blank" rel="noopener noreferrer">Download ZIP</a>`
      : '';
    return `<li><strong>Iteration ${iterationNumber}</strong> - Revision ${escapeHtml(revisionNumber)}${currentTag}${entryDownloadHtml ? ` - ${entryDownloadHtml}` : ''}</li>`;
  }).join('');

  const restoreChoices = history
    .filter((entry) => Number(entry.iterationNumber ?? 0) !== currentIterationNumber)
    .map((entry) => ({
      option: `Iteration ${Number(entry.iterationNumber ?? 0) || 0} (rev ${Number(entry.revisionNumber ?? 0) || 0})`,
    }));

  const formFields = [
    {
      fieldLabel: 'Approved',
      fieldName: 'Approved',
      fieldType: 'dropdown',
      fieldOptions: {
        values: [
          { option: 'approved' },
          { option: 'rejected' },
        ],
      },
      requiredField: true,
    },
    {
      fieldLabel: 'Restore older iteration',
      fieldName: 'Restore older iteration',
      fieldType: 'dropdown',
      fieldOptions: {
        values: [
          { option: 'Yes' },
          { option: 'No' },
        ],
      },
      defaultValue: 'No',
      requiredField: true,
    },
    {
      fieldLabel: 'Iteration to restore',
      fieldName: 'Iteration to restore',
      fieldType: 'dropdown',
      fieldOptions: {
        values: restoreChoices,
      },
    },
    {
      fieldLabel: 'Attachments (optional)',
      fieldName: 'Attachments',
      fieldType: 'file',
    },
    {
      fieldLabel: 'Feedback',
      fieldName: 'Feedback',
      fieldType: 'textarea',
      placeholder: 'Describe exactly what should change in the design package.',
    },
  ];

  const descriptionHtml = [
    '<p>Review the current Design ZIP, then approve it or request changes.</p>',
    currentDownloadHtml,
    restoreError ? `<p><strong>${escapeHtml(restoreError)}</strong></p>` : '',
    '<p>If you want to return to a previously generated version, choose Yes in Restore older iteration. You can also download any generated iteration below.</p>',
    historyItemsHtml ? `<p>Generated iterations:</p><ol>${historyItemsHtml}</ol>` : '<p>No generated iterations are available yet.</p>',
  ].filter(Boolean).join('');

  return {
    descriptionHtml,
    formJson: JSON.stringify(formFields),
  };
};

const existingHistory = Array.isArray(json.designHistory)
  ? json.designHistory.filter((entry) => entry && typeof entry === 'object')
  : [];

const normalizedHistory = existingHistory.map((entry, index) => ({
  iterationNumber: Number(entry.iterationNumber ?? index + 1) || (index + 1),
  revisionNumber: Number(entry.revisionNumber ?? 0) || 0,
  designStructure: String(entry.designStructure ?? entry.response ?? '').trim(),
  zipDownloadUrl: String(entry.zipDownloadUrl ?? '').trim(),
  zipDownloadToken: String(entry.zipDownloadToken ?? '').trim(),
  downloadLinkHtml: String(entry.downloadLinkHtml ?? '').trim(),
  binaryPropertyName: String(entry.binaryPropertyName ?? '').trim(),
  fileCount: Number(entry.fileCount ?? 0) || 0,
  files: Array.isArray(entry.files) ? entry.files : [],
}));

const currentEntry = {
  revisionNumber: Number(json.revisionNumber ?? 0) || 0,
  designStructure: String(json.designStructure ?? json.response ?? '').trim(),
  zipDownloadUrl: String(json.zipDownloadUrl ?? '').trim(),
  zipDownloadToken: String(json.zipDownloadToken ?? '').trim(),
  downloadLinkHtml: String(json.downloadLinkHtml ?? '').trim(),
  fileCount: Number(json.fileCount ?? 0) || 0,
  files: Array.isArray(json.files) ? json.files : [],
};

const isSameEntry = (entry) =>
  entry.revisionNumber === currentEntry.revisionNumber &&
  entry.zipDownloadToken === currentEntry.zipDownloadToken &&
  entry.zipDownloadUrl === currentEntry.zipDownloadUrl &&
  entry.designStructure === currentEntry.designStructure;

let storedEntry = normalizedHistory.find(isSameEntry);

const usedBinaryPropertyNames = new Set(
  normalizedHistory
    .map((entry) => String(entry.binaryPropertyName ?? '').trim())
    .filter(Boolean),
);

if (!storedEntry) {
  const nextIterationNumber = normalizedHistory.reduce(
    (maxValue, entry) => Math.max(maxValue, Number(entry.iterationNumber ?? 0) || 0),
    0,
  ) + 1;

  let binaryPropertyName = '';
  if (binary.designZip) {
    let suffix = nextIterationNumber;
    do {
      binaryPropertyName = `design_iteration_${suffix}`;
      suffix += 1;
    } while (usedBinaryPropertyNames.has(binaryPropertyName) || binary[binaryPropertyName]);
    binary[binaryPropertyName] = binary.designZip;
  }

  storedEntry = {
    iterationNumber: nextIterationNumber,
    ...currentEntry,
    binaryPropertyName,
  };
  normalizedHistory.push(storedEntry);
} else if (!storedEntry.binaryPropertyName && binary.designZip) {
  let suffix = Number(storedEntry.iterationNumber ?? normalizedHistory.length + 1) || (normalizedHistory.length + 1);
  let binaryPropertyName = '';
  do {
    binaryPropertyName = `design_iteration_${suffix}`;
    suffix += 1;
  } while (usedBinaryPropertyNames.has(binaryPropertyName) || binary[binaryPropertyName]);
  binary[binaryPropertyName] = binary.designZip;
  storedEntry.binaryPropertyName = binaryPropertyName;
}

json.designHistory = normalizedHistory;
json.currentDesignIterationNumber = Number(storedEntry.iterationNumber ?? 0) || 0;

const reviewAssets = buildDesignReviewAssets({
  history: normalizedHistory,
  currentIterationNumber: json.currentDesignIterationNumber,
  currentZipDownloadUrl: json.zipDownloadUrl,
  restoreError: '',
});
json.designReviewDescriptionHtml = reviewAssets.descriptionHtml;
json.designReviewFormJson = reviewAssets.formJson;

delete json.designHistoryHtml;

const preservedBinary = {};
for (const [name, value] of Object.entries(binary)) {
  if (name === 'requirements' || name === 'designSpec' || name === 'designZip' || name === 'reviewZip' || /^design_iteration_\d+$/.test(name)) {
    preservedBinary[name] = value;
  }
}

return [{
  json,
  ...(Object.keys(preservedBinary).length ? { binary: preservedBinary } : {}),
}];

