  const currentDownloadUrl = String(currentZipDownloadUrl ?? '').trim();
  const currentDownloadHtml = currentDownloadUrl
    ? `<p><a href="${escapeHtml(currentDownloadUrl)}" download target="_blank" rel="noopener noreferrer">Download current Design ZIP</a></p>`
    : '';

  const historyItemsHtml = history.map((entry) => {
    const iterationNumber = Number(entry.iterationNumber ?? 0) || 0;
    const revisionNumber = Number(entry.revisionNumber ?? 0) || 0;
    const currentTag = iterationNumber === currentIterationNumber ? ' <strong>(current)</strong>' : '';
    const entryDownloadUrl = String(entry.zipDownloadUrl ?? '').trim();
    const entryDownloadHtml = entryDownloadUrl
      ? `<a href="${escapeHtml(entryDownloadUrl)}" download target="_blank" rel="noopener noreferrer">Download ZIP</a>`
      : '';
    return `<li><strong>Iteration ${iterationNumber}</strong> - Revision ${escapeHtml(revisionNumber)}${currentTag}${entryDownloadHtml ? ` - ${entryDownloadHtml}` : ''}</li>`;
  }).join('');

  const restoreChoices = history
    .filter((entry) => Number(entry.iterationNumber ?? 0) !== currentIterationNumber)
    .map((entry) => ({
      option: `Iteration ${Number(entry.iterationNumber ?? 0) || 0} (rev ${Number(entry.revisionNumber ?? 0) || 0})`,
    }));

  const formFields = [
    {
      fieldLabel: 'Approved',
      fieldName: 'Approved',
      fieldType: 'dropdown',
      fieldOptions: {
        values: [
          { option: 'approved' },
          { option: 'rejected' },
        ],
      },
      requiredField: true,
    },
    {
