      fieldName: 'Restore older iteration',
      fieldType: 'dropdown',
      fieldOptions: {
        values: [
          { option: 'Yes' },
          { option: 'No' },
        ],
      },
      defaultValue: 'No',
      requiredField: true,
    },
    {
      fieldLabel: 'Iteration to restore',
      fieldName: 'Iteration to restore',
      fieldType: 'dropdown',
      fieldOptions: {
        values: restoreChoices,
      },
    },
    {
      fieldLabel: 'Attachments (optional)',
      fieldName: 'Attachments',
      fieldType: 'file',
    },
    {
      fieldLabel: 'Feedback',
      fieldName: 'Feedback',
      fieldType: 'textarea',
      placeholder: 'Describe exactly what should change in the design package.',
    },
  ];

  const descriptionHtml = [
    '<p>Review the current Design ZIP, then approve it or request changes.</p>',
    currentDownloadHtml,
    restoreError ? `<p><strong>${escapeHtml(restoreError)}</strong></p>` : '',
    '<p>If you want to return to a previously generated version, choose Yes in Restore older iteration. You can also download any generated iteration below.</p>',
    historyItemsHtml ? `<p>Generated iterations:</p><ol>${historyItemsHtml}</ol>` : '<p>No generated iterations are available yet.</p>',
  ].filter(Boolean).join('');

  return {
    descriptionHtml,
    formJson: JSON.stringify(formFields),
  };
};

const selectionLabel = String(json['Iteration to restore'] ?? '').trim();
const selectionMatch = selectionLabel.match(/Iteration\s+(\d+)/i);
const selectedIterationNumber = selectionMatch ? Number.parseInt(selectionMatch[1], 10) : Number.NaN;
const currentIterationNumber = Number(json.currentDesignIterationNumber ?? 0) || 0;
const selectedEntry = history.find((entry) => Number(entry.iterationNumber ?? 0) === selectedIterationNumber);

if (selectedEntry && Number(selectedEntry.iterationNumber ?? 0) !== currentIterationNumber) {
  json.designStructure = String(selectedEntry.designStructure ?? selectedEntry.response ?? json.designStructure ?? json.response ?? '').trim();
  json.response = json.designStructure;
  json.fileCount = Number(selectedEntry.fileCount ?? json.fileCount ?? 0) || 0;
  json.files = Array.isArray(selectedEntry.files) ? selectedEntry.files : (Array.isArray(json.files) ? json.files : []);
  json.revisionNumber = Number(selectedEntry.revisionNumber ?? json.revisionNumber ?? 0) || 0;
  json.zipDownloadUrl = String(selectedEntry.zipDownloadUrl ?? json.zipDownloadUrl ?? '').trim();
  json.zipDownloadToken = String(selectedEntry.zipDownloadToken ?? json.zipDownloadToken ?? '').trim();
  json.downloadLinkHtml = String(selectedEntry.downloadLinkHtml ?? json.downloadLinkHtml ?? '').trim();
  json.currentDesignIterationNumber = Number(selectedEntry.iterationNumber ?? json.currentDesignIterationNumber ?? 0) || 0;
  json.fileCount = Number(selectedEntry.fileCount ?? json.fileCount ?? 0) || 0;
  json.files = Array.isArray(selectedEntry.files) ? selectedEntry.files : (Array.isArray(json.files) ? json.files : []);

  const binaryPropertyName = String(selectedEntry.binaryPropertyName ?? '').trim();
  if (binaryPropertyName && binary[binaryPropertyName]) {
    binary.designZip = binary[binaryPropertyName];
    binary.reviewZip = binary[binaryPropertyName];
  }

  delete json.restoreSelectionError;
} else {
  json.restoreSelectionError = 'Select one of the previously generated iterations to restore it.';
}

const reviewAssets = buildDesignReviewAssets({
  history,
  currentIterationNumber: Number(json.currentDesignIterationNumber ?? 0) || 0,
  currentZipDownloadUrl: json.zipDownloadUrl,
  restoreError: String(json.restoreSelectionError ?? '').trim(),
});
json.designReviewDescriptionHtml = reviewAssets.descriptionHtml;
json.designReviewFormJson = reviewAssets.formJson;

delete json.designHistoryHtml;
delete json.reviewMode;
delete json.feedback;
delete json.Feedback;
delete json.Approved;
delete json.Attachments;
delete json['Restore older iteration'];
delete json['Iteration to restore'];

const preservedBinary = {};
for (const [name, value] of Object.entries(binary)) {
  if (name === 'requirements' || name === 'designSpec' || name === 'designZip' || name === 'reviewZip' || /^design_iteration_\d+$/.test(name)) {
    preservedBinary[name] = value;
  }
}

return [{
  json,
  ...(Object.keys(preservedBinary).length ? { binary: preservedBinary } : {}),
}];

const item = $input.first() ?? { json: {}, binary: {} };
return [{
  json: {
    ...(item.json ?? {}),
    reviewMode: 'refine',
  },
  ...(item.binary && Object.keys(item.binary).length ? { binary: item.binary } : {}),
}];

const item = $input.first() ?? { json: {}, binary: {} };
const json = { ...(item.json ?? {}) };
const binary = { ...(item.binary ?? {}) };

const history = Array.isArray(json.designHistory)
  ? json.designHistory.filter((entry) => entry && typeof entry === 'object')
  : [];

const currentIterationNumber = Number(json.currentDesignIterationNumber ?? 0) || 0;
const currentZipDownloadToken = String(json.zipDownloadToken ?? '').trim();

let designZip = binary.designZip || binary.reviewZip;

const findEntryByToken = (token) => {
  if (!token) return null;
  return history.find((entry) => String(entry.zipDownloadToken ?? '').trim() === token) ?? null;
};

const findEntryByIteration = (iterationNumber) => {
  if (!(iterationNumber > 0)) return null;
  return history.find((entry) => (Number(entry.iterationNumber ?? 0) || 0) === iterationNumber) ?? null;
};

const resolvedEntry = findEntryByToken(currentZipDownloadToken) || findEntryByIteration(currentIterationNumber);

if (resolvedEntry) {
  const binaryPropertyName = String(resolvedEntry.binaryPropertyName ?? '').trim();
  if (binaryPropertyName && binary[binaryPropertyName]) {
    designZip = binary[binaryPropertyName];
  }

  json.revisionNumber = Number(resolvedEntry.revisionNumber ?? json.revisionNumber ?? 0) || 0;
  json.fileCount = Number(resolvedEntry.fileCount ?? json.fileCount ?? 0) || 0;
  json.zipDownloadUrl = String(resolvedEntry.zipDownloadUrl ?? json.zipDownloadUrl ?? '').trim();
  json.zipDownloadToken = String(resolvedEntry.zipDownloadToken ?? json.zipDownloadToken ?? '').trim();
  json.currentDesignIterationNumber = Number(resolvedEntry.iterationNumber ?? json.currentDesignIterationNumber ?? 0) || 0;
}

if (!designZip) {
  throw new Error('Approved design ZIP is missing.');
}

return [{
  json: {
    revisionNumber: Number(json.revisionNumber ?? 0) || 0,
    fileCount: Number(json.fileCount ?? 0) || 0,
    zipDownloadUrl: String(json.zipDownloadUrl ?? '').trim(),
    zipDownloadToken: String(json.zipDownloadToken ?? '').trim(),
    currentDesignIterationNumber: Number(json.currentDesignIterationNumber ?? 0) || 0,
  },
  binary: {
    designZip,
  },
}];
